  1002→/// Returns the default cache-level tile sizes for a matmul op and a specific
  1003→/// target. There shouldn't be proper heuristics here, just fixed values.
  1004→static SmallVector<int64_t> getDefaultMatmulCacheSizes(linalg::LinalgOp op,
  1005→                                                       bool isQuantized) {
  1006→  unsigned numLoops = op.getNumLoops();
  1007→  SmallVector<int64_t> noCacheLevelTiling(numLoops, 0);
  1008→
  1009→  // Cache-level tiling is only supported for 2-D matmuls.
  1010→  if (numLoops < 3) {
  1011→    return noCacheLevelTiling;
  1012→  }
  1013→
  1014→  auto targetAttr = IREE::HAL::ExecutableTargetAttr::lookup(op);
  1015→  if (isX86(targetAttr)) {
  1016→    if (isQuantized) {
  1017→      return noCacheLevelTiling;
  1018→    }
  1019→
  1020→    SmallVector<int64_t> defaultCacheTileSizes(numLoops - 3, 0);
  1021→    defaultCacheTileSizes.append({8, 128, 16});
  1022→    return defaultCacheTileSizes;
  1023→  }
  1024→
  1025→  return noCacheLevelTiling;
  1026→}
