  1028→static LogicalResult setMatmulPeelingRootConfig(
  1029→    mlir::FunctionOpInterface entryPointFn, linalg::ContractionOpInterface op,
  1030→    ArrayRef<int64_t> distTileSizes, ArrayRef<int64_t> cacheTileSizes,
  1031→    ArrayRef<bool> inputVecScalableTileFlags, ArrayRef<int64_t> vecTileSizes,
  1032→    int vectorSize) {
  1033→
  1034→  // 0. Preprocess for scalable vectors
  1035→  SmallVector<int64_t> roundedVecTileSizes(vecTileSizes);
  1036→
  1037→  // The LLVM backend struggles to legalize non-power-of-two scalable vectors,
  1038→  // hence the extra rounding up.
  1039→  for (const auto &[index, size] : llvm::enumerate(roundedVecTileSizes)) {
  1040→    if (!size)
  1041→      continue;
  1042→    roundedVecTileSizes[index] =
  1043→        roundUpToPow2(size,
  1044→                      /*predicate=*/inputVecScalableTileFlags[index]);
  1045→  }
  1046→
  1047→  // 1. Compute tile sizes for all tiling levels.
  1048→  // The tiling for parallel dims (M and N) and reduction dim (K) should be
  1049→  // separated, so we move K dim from parallel tile sizes to reduction tile
  1050→  // sizes.
  1051→  int64_t numTilingDims = vecTileSizes.size();
  1052→  SmallVector<int64_t> cacheParallelTileSizes(cacheTileSizes.begin(),
  1053→                                              cacheTileSizes.end());
  1054→  SmallVector<int64_t> cacheReductionTileSizes(numTilingDims, 0);
  1055→  std::swap(cacheParallelTileSizes.back(), cacheReductionTileSizes.back());
  1056→
  1057→  SmallVector<int64_t> vectorParallelTileSizes(roundedVecTileSizes.begin(),
  1058→                                               roundedVecTileSizes.end());
  1059→  SmallVector<int64_t> vectorReductionTileSizes(numTilingDims, 0);
  1060→  std::swap(vectorParallelTileSizes.back(), vectorReductionTileSizes.back());
  1061→
  1062→  TileSizesListType tileSizes = {
  1063→      SmallVector<int64_t>(distTileSizes), cacheParallelTileSizes,
  1064→      cacheReductionTileSizes, vectorParallelTileSizes,
  1065→      vectorReductionTileSizes};
  1066→  // No need for tiling inner parallel dims.
  1067→  tileSizes.emplace_back(numTilingDims, 0);
  1068→
  1069→  // 2. Set scalable flags for all the tiling levels.
  1070→  SmallVector<bool> parallelScalableFlags(inputVecScalableTileFlags.begin(),
  1071→                                          inputVecScalableTileFlags.end());
  1072→  SmallVector<bool> reductionScalableFlags(numTilingDims, false);
  1073→  std::swap(parallelScalableFlags.back(), reductionScalableFlags.back());
  1074→
  1075→  ScalableTileFlagsListType newScalableTileFlags;
  1076→  // No scalable:
  1077→  // * distribution,
  1078→  // * cache parallel, and
  1079→  // * cache reduction
  1080→  // tile sizes.
  1081→  newScalableTileFlags.emplace_back(numTilingDims, false);
  1082→  newScalableTileFlags.emplace_back(numTilingDims, false);
  1083→  newScalableTileFlags.emplace_back(numTilingDims, false);
  1084→
  1085→  newScalableTileFlags.push_back(parallelScalableFlags);
  1086→  newScalableTileFlags.push_back(reductionScalableFlags);
  1087→
  1088→  // No scalable inner parallel dims.
  1089→  newScalableTileFlags.emplace_back(numTilingDims, false);
  1090→
  1091→  LLVM_DEBUG(KD_DBGS() << "Final tile sizes for contraction: " << tileSizes
  1092→                       << "\n");
  1093→  LLVM_DEBUG(KD_DBGS() << "Final tile scalable flags for contraction: "
  1094→                       << newScalableTileFlags << "\n");
  1095→
  1096→  DictionaryAttr pipelineConfig =
  1097→      getPipelineConfWithPeelingAttr(op.getContext());
  1098→  return setOpConfigAndEntryPointFnTranslation(
  1099→      entryPointFn, op, tileSizes, newScalableTileFlags,
  1100→      DispatchLoweringPassPipeline::CPUDoubleTilingExpert,
  1101→      /*workgroupSize=*/{}, /*subgroupSize=*/{}, pipelineConfig);
  1102→}
