  1104→static LogicalResult
  1105→setMatmulRootConfig(mlir::FunctionOpInterface entryPointFn,
  1106→                    linalg::ContractionOpInterface op,
  1107→                    const TileSizesListTypeRef inputTileSizes,
  1108→                    const ScalableTileFlagsListTypeRef inputScalableTileFlags,
  1109→                    int vectorSize, VectorPreProcStrategy vecPreProcStrategy) {
  1110→  auto linalgOp = cast<linalg::LinalgOp>(op.getOperation());
  1111→  SmallVector<int64_t> shape = linalgOp.getStaticLoopRanges();
  1112→
  1113→  // The tiling for parallel dims and reduction dims are separated.
  1114→  const SmallVectorImpl<int64_t> &inputVecTileSizes = inputTileSizes.back();
  1115→  const SmallVectorImpl<bool> &vecScalableDims = inputScalableTileFlags.back();
  1116→  SmallVector<int64_t> vecTileSizes;
  1117→  SmallVector<bool> parallelScalableFlags;
  1118→  int numScalableDims = llvm::count(vecScalableDims, true);
  1119→
  1120→  for (auto [index, tileSize] : llvm::enumerate(inputVecTileSizes)) {
  1121→    int64_t sz = tileSize;
  1122→    bool isScalable = vecScalableDims[index];
  1123→    // The backend struggles to legalize non-power-of-two scalable vectors.
  1124→    bool enforcePowerOfTwo = isScalable;
  1125→
  1126→    // Ad-hoc: Don't attempt to resize scalable tiles when numScalableDims >= 2.
  1127→    // For ArmSME (the only current user of 2D scalable vectors), tile sizes
  1128→    // must match SME tiles (and cannot be arbitrarily resized).
  1129→    if (sz != 0 && (numScalableDims < 2 || !isScalable)) {
  1130→      sz = getMaxVectorTileSize(
  1131→          /*numElem=*/shape[index],
  1132→          /*tileSize=*/sz, vectorSize, enforcePowerOfTwo);
  1133→    }
  1134→    vecTileSizes.push_back(sz);
  1135→    // 1x scalable vectors e.g. vector<[1]xty> are also poorly supported, so
  1136→    // fallback to fixed vectorization if they occur:
  1137→    parallelScalableFlags.push_back(sz > 1 ? isScalable : false);
  1138→  }
  1139→  limitVectorTileSizes(cast<linalg::LinalgOp>(op.getOperation()), vecTileSizes);
  1140→  SmallVector<int64_t> parallelTileSizes = vecTileSizes;
  1141→  SmallVector<int64_t> reductionTileSizes;
  1142→  SmallVector<bool> reductionScalableFlags;
  1143→  splitParallelAndReductionTiles(op, parallelTileSizes, reductionTileSizes,
  1144→                                 &parallelScalableFlags,
  1145→                                 &reductionScalableFlags);
  1146→
  1147→  if (vecPreProcStrategy == VectorPreProcStrategy::None) {
  1148→    setVectorSizesForDynamicShapes(cast<linalg::LinalgOp>(op.getOperation()),
  1149→                                   vecPreProcStrategy, parallelTileSizes,
  1150→                                   reductionTileSizes);
  1151→  }
  1152→
  1153→  // Ensure there's no zero scalable dims.
  1154→  int64_t numTilingDims = parallelTileSizes.size();
  1155→  for (unsigned i = 0; i < numTilingDims; i++) {
  1156→    if (reductionTileSizes[i] == 0)
  1157→      reductionScalableFlags[i] = false;
  1158→    if (parallelTileSizes[i] == 0)
  1159→      parallelScalableFlags[i] = false;
  1160→  }
  1161→
  1162→  TileSizesListType newTileSizes;
  1163→  // Copy all the tile size levels except the vector tile sizes which are split
  1164→  // into parallel and reduction.
  1165→  std::copy(inputTileSizes.begin(), inputTileSizes.end() - 1,
  1166→            std::back_inserter(newTileSizes));
  1167→  newTileSizes.push_back(parallelTileSizes);
  1168→  newTileSizes.push_back(reductionTileSizes);
  1169→  // No need for tiling inner parallel dims.
  1170→  newTileSizes.emplace_back(numTilingDims, 0);
  1171→
  1172→  // Mirror the same layout for the scalable dims.
  1173→  ScalableTileFlagsListType newScalableTileFlags;
  1174→  std::copy(inputScalableTileFlags.begin(), inputScalableTileFlags.end() - 1,
  1175→            std::back_inserter(newScalableTileFlags));
  1176→  newScalableTileFlags.push_back(parallelScalableFlags);
  1177→  newScalableTileFlags.push_back(reductionScalableFlags);
  1178→  // No scalable inner parallel dims.
  1179→  newScalableTileFlags.emplace_back(numTilingDims, false);
  1180→
  1181→  LLVM_DEBUG(KD_DBGS() << "Final tile sizes for contraction: " << newTileSizes
  1182→                       << "\n");
  1183→  LLVM_DEBUG(KD_DBGS() << "Final tile scalable flags for contraction: "
  1184→                       << newScalableTileFlags << "\n");
  1185→
  1186→  auto pipeline = DispatchLoweringPassPipeline::CPUDoubleTilingExpert;
  1187→  DictionaryAttr pipelineConfig;
  1188→  if (vecPreProcStrategy == VectorPreProcStrategy::Peeling) {
  1189→    pipelineConfig = getPipelineConfWithPeelingAttr(op.getContext());
  1190→  }
  1191→
  1192→  return setOpConfigAndEntryPointFnTranslation(
  1193→      entryPointFn, op, newTileSizes, newScalableTileFlags, pipeline,
  1194→      /*workgroupSize=*/{}, /*subgroupSize=*/{}, pipelineConfig);
