  1199→static void
  1200→getDefaultMatmulVectorSizes(linalg::LinalgOp op, int64_t vectorSize,
  1201→                            SmallVectorImpl<int64_t> &sizes,
  1202→                            SmallVectorImpl<bool> &scalableSizeFlags) {
