  1207→    } else {
  1208→      sizes.append({1, 1, vectorSize});
  1209→    }
  1210→    return;
  1211→  }
  1212→
  1213→  if (isAArch64(targetAttr)) {
  1214→    sizes.append({8, 16, 1});
  1215→
  1216→    // Specialisation for scalable vectorization.
  1217→    if (clEnableScalableVectorization && hasAnySVEFeature(targetAttr)) {
  1218→      // Mark middle dimensions as scalable, so sizes are (8, [16], 1).
  1219→      scalableSizeFlags.append({false, true, false});
  1220→    }
  1221→    return;
  1222→  }
  1223→
  1224→  if (isRISCV(targetAttr)) {
  1225→    // RISC-V natively supports scalar x vector operations so we don't have to
  1226→    // vectorize dimension k. Vectorizing dimension k results in a vector load
  1227→    // and a sequence of vrgather ops to implemement the broadcast explicitly.
  1228→    // We should tile and/or unroll that dimension without vectorization, which
  1229→    // is not possible right now.
  1230→    sizes.append({8, 32, 1});
  1231→    return;
  1232→  }
  1233→
  1234→  // Fallback to use vectorSize for unknown arch.
  1235→  sizes.append(3, vectorSize);
  1236→  return;
  1237→}
