  1239→/// Checks if the input and output types of a linalg op are the same, and if so
  1240→/// returns the type. Otherwise, returns failure.
  1241→static FailureOr<Type> nonWideningLinalgElementType(linalg::LinalgOp op) {
  1242→  SmallVector<Type, 3> inputAndOutputElementTypes;
  1243→  for (Value v :
  1244→       llvm::concat<Value>(op.getRegionInputArgs(), op.getRegionOutputArgs())) {
  1245→    inputAndOutputElementTypes.push_back(v.getType());
  1246→  }
  1247→  assert(!inputAndOutputElementTypes.empty() &&
  1248→         "expected linalg op to have input and output types");
  1249→  if (!llvm::all_equal(inputAndOutputElementTypes))
  1250→    return failure();
  1251→  return inputAndOutputElementTypes[0];
  1252→}
  1253→
  1254→/// Compute or adjust existing vector sizes using a generic heuristic that will
  1255→/// aim to fill at least one full vector register for all the element types of
  1256→/// the matmul. For now, the current heuristics only look at the N dimension but
  1257→/// we would introduce logic to also consider unrolling trade-offs between the
  1258→/// M, N and K.
  1259→///
  1260→/// Example: for an (i32 <- i8, i8) matmul and a 128-bit vector register, vector
  1261→/// size N would be at least 128/8=16.
  1262→///
  1263→/// NOTE: This function should not contain target-specific conditional code.
  1264→/// TODO: Currently it's only use on Aarch64. We should generalize it to other
  1265→/// targets.
  1266→static void getMatmulVectorSizesUsingFullVectorHeuristics(
  1267→    mlir::FunctionOpInterface entryPointFn, linalg::LinalgOp op,
  1268→    int64_t vectorSize, SmallVectorImpl<int64_t> &sizes,
  1269→    SmallVectorImpl<bool> &scalableSizeFlags) {
  1270→  if (sizes.empty())
  1271→    getDefaultMatmulVectorSizes(op, vectorSize, sizes, scalableSizeFlags);
  1272→
  1273→  // Find the smallest type size in the matmul.
  1274→  SmallVector<Type> matmulTypes;
  1275→  auto operandTypes = op->getOperandTypes();
  1276→  matmulTypes.append(operandTypes.begin(), operandTypes.end());
  1277→  auto resultTypes = op->getResultTypes();
  1278→  matmulTypes.append(resultTypes.begin(), resultTypes.end());
  1279→
  1280→  int64_t minSize = std::numeric_limits<int64_t>::max();
  1281→  for (Type mmType : matmulTypes) {
  1282→    if (auto shType = dyn_cast<ShapedType>(mmType))
  1283→      mmType = shType.getElementType();
  1284→
  1285→    if (mmType.isSignlessIntOrFloat())
  1286→      minSize = std::min<int64_t>(minSize, mmType.getIntOrFloatBitWidth());
  1287→  }
  1288→
  1289→  LLVM_DEBUG(KD_DBGS() << "Smallest type found: " << minSize << " bits\n");
  1290→  assert(minSize > 0 && minSize < std::numeric_limits<int64_t>::max() &&
  1291→         "Min size couldn't be computed");
  1292→
  1293→  // Make sure that the smallest type can at least fill a full vector register
  1294→  // given the tile size of the main vector dimension (N).
  1295→  constexpr int64_t byteSizeInBits = 8;
  1296→  int64_t minNumElements =
  1297→      (getNativeVectorSizeInBytes(entryPointFn) * byteSizeInBits) / minSize;
  1298→  sizes[1] = std::max<int64_t>(sizes[1], minNumElements);
  1299→}
