  1301→/// Utility to compute the tile sizes for RISC-V Vector.
  1302→/// For now, it only supports nonWideningLinalgElementType float.
  1303→/// TileSize is set to m = 7, n = maxNumberElementsForLMUL4, and k = 1.
  1304→///
  1305→/// Example: for an pure f32-matmul and a 512-bit vector register.
  1306→/// nativeVectorSize is equal to VLEN * LMUL2 / 8, so it's 128.
  1307→/// maxNumberElementsForLMUL4 = 128 * 2 * 8 / 32 = 64.
  1308→///
  1309→/// TODO: Currently it only supports for nonWideningLinalgElementType.
  1310→static void
  1311→getMatmulRISCVVectorSizes(mlir::FunctionOpInterface entryPointFn,
  1312→                          linalg::LinalgOp op, int64_t vectorSize,
  1313→                          SmallVectorImpl<int64_t> &sizes,
  1314→                          SmallVectorImpl<bool> &scalableSizeFlags) {
  1315→  if (sizes.empty())
  1316→    getDefaultMatmulVectorSizes(op, vectorSize, sizes, scalableSizeFlags);
  1317→  // TODO: support widening matmul.
  1318→  // Determines n dimension tile size with VLEN for
  1319→  // nonWideningLinalgElementType.
  1320→  FailureOr<Type> elementType = nonWideningLinalgElementType(op);
  1321→  if (failed(elementType))
  1322→    return;
  1323→
  1324→  // nativeVectorSize is cacluated with VLEN and LMUL=2.
  1325→  int64_t nativeVectorSize = getNativeVectorSizeInBytes(entryPointFn);
  1326→  int64_t elementSize;
  1327→  if (elementType->isF16()) {
  1328→    elementSize = 16;
  1329→  } else if (elementType->isF32()) {
  1330→    elementSize = 32;
  1331→  } else if (elementType->isF64()) {
  1332→    elementSize = 64;
  1333→  } else {
  1334→    // TODO: support int data type
  1335→    return;
  1336→  }
  1337→  FailureOr<linalg::ContractionDimensions> cDims =
  1338→      linalg::inferContractionDims(op);
  1339→  if (failed(cDims) || cDims->m.size() != 1)
  1340→    return;
  1341→  // Use 7 x lmul4 to fully utilize vector registers.
  1342→  sizes[0] = 7;
  1343→  // Calculate tile size for the main vector dimension (N).
  1344→  constexpr int64_t kByteSizeInBits = 8;
  1345→  int64_t maxNumberElementsForLMUL4 =
  1346→      (nativeVectorSize * 2 * kByteSizeInBits) / elementSize;
  1347→  sizes[1] = maxNumberElementsForLMUL4;
  1348→  sizes[2] = 1;
  1349→  ArrayRef<int64_t> lhsShape = op.getShape(op.getDpsInputOperand(0));
  1350→  // If m = 1, set tile size to 1 x lmul8
  1351→  if (lhsShape[cDims->m[0]] == 1) {
  1352→    sizes[0] = 1;
  1353→    sizes[1] *= 2;
  1354→  }
  1355→}
