  1357→/// Utility to compute the tile sizes for AArch64 SME. Unlike other targets, the
  1358→/// tile sizes picked here must exactly match multiples of the SME hardware
  1359→/// virtual tiles, as there is currently no support for lowering non-standard
  1360→/// shapes.
  1361→static void
  1362→getMatmulAArch64SMEVectorSizes(linalg::LinalgOp op,
  1363→                               SmallVectorImpl<int64_t> &sizes,
  1364→                               SmallVectorImpl<bool> &scalableSizeFlags) {
  1365→  // Double-check the operation is one that is supported for lowering to ArmSME.
  1366→  if (!llvm::isa<linalg::MatmulOp, linalg::MatmulTransposeAOp>(op))
  1367→    return;
  1368→
  1369→  auto elementType = nonWideningLinalgElementType(op);
  1370→  if (failed(elementType))
  1371→    return;
  1372→
  1373→  // TODO(macdue): Come up with some heuristics to pick the appropriate tiling
  1374→  // for SME, i.e. optimal layout based on static sizes.
  1375→
  1376→  if (elementType->isF32()) {
  1377→    // Tile for [8]x[8], this results in equal loads from both the A and B
  1378→    // matrices and will use all four [4]x[4] 32-bit SME accumulators.
  1379→    sizes.append({8, 8, 1});
  1380→    scalableSizeFlags.append({true, true, false});
  1381→  }
  1382→
  1383→  if (elementType->isF64()) {
  1384→    // Tile for [4]x[8], this results in loading twice as much from matrix B
  1385→    // than and will use all eight [2]x[2] 64-bit SME accumulators.
  1386→    // The B dimension is larger as it is known to be contiguous.
  1387→    sizes.append({4, 8, 1});
  1388→    scalableSizeFlags.append({true, true, false});
  1389→  }
  1390→
  1391→  // TODO(macdue): Other element types (there is little support for anything
  1392→  // other than f32 and f64 yet).
  1393→}
