  1723→static bool isPackMatmulLHS(tensor::PackOp op) {
  1724→  // linalg.batch_matmul LHS shape
  1725→  if (op.getSourceRank() == 3 && op.getInnerDimsPos().size() == 2 &&
  1726→      op.getInnerDimsPos()[0] == 1 && op.getInnerDimsPos()[1] == 2) {
  1727→    return true;
  1728→  }
  1729→  // linalg.matmul LHS shape
  1730→  return op.getSourceRank() == 2 && op.getInnerDimsPos().size() == 2 &&
  1731→         op.getInnerDimsPos()[0] == 0 && op.getInnerDimsPos()[1] == 1;
  1732→}
