  1734→/// Returns vectorization tile sizes for a pack op. It is driven by pack op
  1735→/// configurations and target CPU features.
  1736→static SmallVector<int64_t>
  1737→getPackVectorTileSizes(mlir::FunctionOpInterface entryPointFn,
  1738→                       tensor::PackOp op) {
  1739→  SmallVector<int64_t> tileSizes(op.getSourceRank(), 1);
  1740→  auto targetAttr = IREE::HAL::ExecutableTargetAttr::lookup(entryPointFn);
  1741→  int64_t vectorSize = getVectorSize(entryPointFn, op.getSourceType());
  1742→  if (!hasAVX512fFeature(targetAttr) || !isPackMatmulLHS(op)) {
  1743→    return tileSizes;
  1744→  }
  1745→  if (op.getSourceType().getElementType().isF32()) {
  1746→    tileSizes.back() = vectorSize;
  1747→  }
  1748→  // TODO(#16314): Generate efficient tile sizes for non-f32 cases.
  1749→  if (op.getSourceType().getElementType().isF16()) {
  1750→    // We adjust the vector size to half to use the same lowering strategy as
  1751→    // f32.
  1752→    tileSizes.back() = vectorSize / 2;
  1753→  }
  1754→  return tileSizes;
  1755→}
