  1757→static LogicalResult setRootConfig(mlir::FunctionOpInterface entryPointFn,
  1758→                                   tensor::PackOp op) {
  1759→  assert(!getLoweringConfig(op) && "expected lowering_config is not set");
  1760→
  1761→  int srcRank = op.getSourceRank();
  1762→  SmallVector<int64_t> innerTiles = op.getStaticTiles();
  1763→  ArrayRef<int64_t> dimPos = op.getInnerDimsPos();
  1764→  int64_t vectorSize = getVectorSize(entryPointFn, op.getSourceType());
  1765→
  1766→  DistributionHeuristicConfig distConfig;
  1767→  distConfig.maxTileSizes.resize(srcRank, clDefaultDistTileSize);
  1768→  distConfig.allowIncompleteTile = true;
  1769→  distConfig.vectorSizeHints.resize(srcRank, 1);
  1770→  for (auto pos : dimPos) {
  1771→    distConfig.vectorSizeHints[pos] = vectorSize;
  1772→  }
  1773→  SmallVector<int64_t> distTileSizes =
  1774→      getDefaultDistributedLevelTileSizes(op, distConfig);
  1775→
  1776→  // The default function aims to returns the number of workload per workgroup,
  1777→  // but it does not know that it is working on packed domain. We need to take
  1778→  // inner tile sizes into account and adjust the distribution tile sizes.
  1779→  for (auto [pos, size] : llvm::zip_equal(dimPos, innerTiles)) {
  1780→    if (distTileSizes[pos] == 0 || ShapedType::isDynamic(size))
  1781→      continue;
  1782→    distTileSizes[pos] = distTileSizes[pos] / size;
  1783→    distTileSizes[pos] = std::max<int64_t>(distTileSizes[pos], 1);
  1784→  }
  1785→
  1786→  // Dynamic inner tiles lead to unbounded stack allocation (which is introduced
  1787→  // by tensor.pad op), so we do not decompose the cases. The x86 and risc-v
  1788→  // backends prefer to not decompose the ops.
  1789→  DictionaryAttr pipelineConfig;
  1790→  auto target = IREE::HAL::ExecutableTargetAttr::lookup(entryPointFn);
  1791→  bool hasDynamicInnerTile = llvm::any_of(
  1792→      op.getMixedTiles(), [](OpFoldResult ofr) { return ofr.is<Value>(); });
  1793→  if (!hasDynamicInnerTile && !isX86(target) && !isRISCV(target)) {
  1794→    pipelineConfig = getPipelineConfWithDecompositionAttr(op.getContext());
  1795→  }
  1796→
  1797→  SmallVector<int64_t> vecTileSizes = getPackVectorTileSizes(entryPointFn, op);
  1798→  TileSizesListType tileSizesList = {distTileSizes, vecTileSizes};
  1799→  return setOpConfigAndEntryPointFnTranslation(
  1800→      entryPointFn, op, tileSizesList,
  1801→      DispatchLoweringPassPipeline::CPUDataTiling, /*workgroupSize=*/{},
  1802→      /*subgroupSize=*/{}, pipelineConfig);
  1803→}
