  1805→static LogicalResult setRootConfig(mlir::FunctionOpInterface entryPointFn,
  1806→                                   tensor::UnPackOp op) {
  1807→  DistributionHeuristicConfig distConfig;
  1808→  distConfig.maxTileSizes.resize(op.getDestRank(), clDefaultDistTileSize);
  1809→  SmallVector<int64_t> distTileSizes =
  1810→      getDefaultDistributedLevelTileSizes(op, distConfig);
  1811→
  1812→  // Fixup for making distTileSizes be multiple of inner_tile_sizes.
  1813→  SmallVector<int64_t> innerTiles = op.getStaticTiles();
  1814→  ArrayRef<int64_t> dimPos = op.getInnerDimsPos();
  1815→  for (auto [pos, size] : llvm::zip_equal(dimPos, innerTiles)) {
  1816→    if (distTileSizes[pos] == 0 || ShapedType::isDynamic(size))
  1817→      continue;
  1818→    distTileSizes[pos] = llvm::alignTo(distTileSizes[pos], size);
  1819→  }
  1820→
  1821→  SmallVector<int64_t> tileSizes(op.getDestRank(), 1);
  1822→  for (auto [pos, size] : llvm::zip_equal(dimPos, innerTiles)) {
  1823→    tileSizes[pos] = ShapedType::isDynamic(size) ? 1 : size;
  1824→  }
  1825→
  1826→  // Dynamic inner tiles lead to unbounded stack allocation (which is introduced
  1827→  // by tensor.pad op), so we do not decompose the cases. The x86 and risc-v
  1828→  // backends prefer to not decompose the ops.
  1829→  DictionaryAttr pipelineConfig;
  1830→  auto target = IREE::HAL::ExecutableTargetAttr::lookup(entryPointFn);
  1831→  bool hasDynamicInnerTile = llvm::any_of(
  1832→      op.getMixedTiles(), [](OpFoldResult ofr) { return ofr.is<Value>(); });
  1833→  if (!hasDynamicInnerTile && !isX86(target) && !isRISCV(target)) {
  1834→    pipelineConfig = getPipelineConfWithDecompositionAttr(op.getContext());
  1835→  }
  1836→
  1837→  TileSizesListType tileSizesList = {distTileSizes, tileSizes};
  1838→  return setOpConfigAndEntryPointFnTranslation(
  1839→      entryPointFn, op, tileSizesList,
  1840→      DispatchLoweringPassPipeline::CPUDataTiling, /*workgroupSize=*/{},
  1841→      /*subgroupSize=*/{}, pipelineConfig);
  1842→}
