  1844→static LogicalResult setRootConfig(mlir::FunctionOpInterface entryPointFn,
  1845→                                   IREE::LinalgExt::AttentionOp attnOp) {
  1846→  FailureOr<IREE::LinalgExt::AttentionOpDetail> maybeOpInfo =
  1847→      IREE::LinalgExt::AttentionOpDetail::get(
  1848→          attnOp.getQueryMap(), attnOp.getKeyMap(), attnOp.getValueMap(),
