  2096→/// Utility to return the transpose vector `sizes` for X86. Empty `sizes` on
  2097→/// return indicates failure.
  2098→static void getTransposeX86VectorSizes(
  2099→    linalg::GenericOp genericOp, IREE::HAL::ExecutableTargetAttr targetAttr,
  2100→    ArrayRef<int64_t> minTileSizes, SmallVectorImpl<int64_t> &sizes) {
  2101→  if (!hasAVX2Feature(targetAttr) ||
  2102→      !x86TransposeLoweringPrecondition(genericOp))
  2103→    return;
  2104→
  2105→  if (llvm::count_if(minTileSizes,
  2106→                     [](int64_t tileSize) { return tileSize > 1; }) != 2) {
  2107→    // Transpose patterns are not applicable if vectorizing more or less than
  2108→    // two dims.
  2109→    return;
  2110→  }
  2111→
  2112→  // Make sure that the original tile sizes are greater than or equal to the
  2113→  // tile sizes to be used for the transpose op (e.g., 8x8, 16x16, etc).
  2114→  int64_t targetVectorSize = 8;
  2115→  if (llvm::any_of(minTileSizes, [&](int64_t tileSize) {
  2116→        return tileSize > 1 && tileSize < targetVectorSize;
  2117→      })) {
  2118→    return;
  2119→  }
  2120→
  2121→  // Target 16x16 tile sizes if there are AVX512 features and all the tile sizes
  2122→  // are greater than or equal to 16.
  2123→  if (hasAVX512fFeature(targetAttr) &&
  2124→      llvm::all_of(minTileSizes, [](int64_t tileSize) {
  2125→        return tileSize == 1 || tileSize >= 16;
  2126→      })) {
  2127→    targetVectorSize = 16;
  2128→  }
  2129→
  2130→  // Replace dims to be vectorized with the new tile sizes.
  2131→  sizes.assign(minTileSizes.begin(), minTileSizes.end());
  2132→  std::replace_if(
  2133→      sizes.begin(), sizes.end(), [](int64_t tileSize) { return tileSize > 1; },
  2134→      targetVectorSize);
  2135→}
