  2403→static LogicalResult
  2404→setConvRootConfig(mlir::FunctionOpInterface entryPointFn,
  2405→                  linalg::LinalgOp convOp, ArrayRef<int64_t> targetTileSizes,
  2406→                  int64_t vectorSize,
  2407→                  VectorPreProcStrategy vecPreProcStrategy) {
  2408→  if (!is2DConvOp(convOp) && !is2DDepthConvOp(convOp) &&
  2409→      !is2DPoolingOp(convOp)) {
