  2422→      getDefaultDistributedLevelTileSizes(convOp, distConfig);
  2423→
  2424→  // Shapes of N, OH, OW, OC, KH, KW, (IC)
  2425→  SmallVector<int64_t> shapes = convOp.getStaticLoopRanges();
  2426→  SmallVector<int64_t> vecTileSizes(targetTileSizes.begin(),
  2427→                                    targetTileSizes.end());
