  2434→          getMaxVectorTileSize(tileSize, vecTileSizes[i], vectorSize);
  2435→    }
  2436→  }
  2437→  limitVectorTileSizes(convOp, vecTileSizes);
  2438→  SmallVector<int64_t> parallelTileSizes = vecTileSizes;
  2439→  SmallVector<int64_t> reductionTileSizes;
