  2524→  if (is2DConvOp(op))
  2525→    return {1, 1, vectorSize, vectorSize, 1, 1, vectorSize};
  2526→  if (is2DDepthConvOp(op))
  2527→    return {1, 1, vectorSize, vectorSize, 1, vectorSize};
  2528→  if (is2DPoolingOp(op))
  2529→    return {1, 1, vectorSize, vectorSize, 1, vectorSize};
  2530→  llvm_unreachable("unsupported conv");
  2531→}
  2532→
  2533→static LogicalResult
  2534→setConvInterfaceRootConfig(mlir::FunctionOpInterface entryPointFn,
  2535→                           linalg::ConvolutionOpInterface convOp) {
  2536→  int64_t vectorSize = getVectorSize(
  2537→      entryPointFn, cast<ShapedType>(convOp->getResultTypes()[0]));
  2538→  SmallVector<int64_t> targetTileSizes =
  2539→      getNhwcConvVectorSizes(entryPointFn, convOp, vectorSize);
  2540→
  2541→  // The tiling sizes are for NHWC layout. We need to apply a permutation if
  2542→  // they are in other layout format.
  2543→  Conv2DDimOrder order = getConv2DDimOrder(convOp);
  2544→  switch (order) {
  2545→  case Conv2DDimOrder::Nhwc:
  2546→    break;
  2547→  case Conv2DDimOrder::Nchw:
  2548→    SmallVector<int64_t> perm;
  2549→    if (is2DConvOp(convOp)) {
  2550→      // D.n, D.oh, D.ow,  D.f, D.kh, D.kw, D.c ->
  2551→      // D.n,  D.f, D.oh, D.ow,  D.c, D.kh, D.kw
  2552→      perm = {0, 3, 1, 2, 6, 4, 5};
  2553→    } else if (is2DPoolingOp(convOp)) {
  2554→      // D.n, D.oh, D.ow, D.c, D.kh, D.kw ->
  2555→      // D.n, D.c, D.oh, D.ow, D.kh, D.kw
  2556→      perm = {0, 3, 1, 2, 4, 5};
  2557→    } else if (is2DDepthConvOp(convOp)) {
  2558→      llvm_unreachable("Not implemented yet");
  2559→    }
  2560→    applyPermutationToVector(targetTileSizes, perm);
  2561→    break;
  2562→  }
  2563→
  2564→  auto vecPreProcStrategy =
  2565→      getVectorPreProcStrategy(cast<linalg::LinalgOp>(convOp.getOperation()));
  2566→  return setConvRootConfig(entryPointFn,
  2567→                           cast<linalg::LinalgOp>(convOp.getOperation()),
  2568→                           targetTileSizes, vectorSize, vecPreProcStrategy);
  2569→}
  2570→
  2571→static LogicalResult setRootConfig(mlir::FunctionOpInterface entryPointFn,
  2572→                                   tensor::PadOp padOp) {
  2573→  SmallVector<int64_t> lbs, ubs;
  2574→  getRangeBounds(cast<TilingInterface>(padOp.getOperation()), lbs, ubs);
  2575→
  2576→  int64_t numLoops = lbs.size();
  2577→  unsigned typeWidthInBytes = IREE::Util::getRoundedElementByteWidth(
  2578→      padOp.getResultType().getElementType());
  2579→  int64_t typeVectorSize = getVectorSize(entryPointFn, typeWidthInBytes);
  2580→  DistributionHeuristicConfig distConfig;
  2581→  distConfig.vectorSizeHints.append(numLoops, 1);
  2582→  if (!ShapedType::isDynamic(ubs.back())) {
  2583→    distConfig.vectorSizeHints.back() = std::min(typeVectorSize, ubs.back());
  2584→  }
  2585→
  2586→  SmallVector<int64_t> distTileSizes =
  2587→      getDefaultDistributedLevelTileSizes(padOp, distConfig);
  2588→  // No further tiling for reduction and inner parallel loops.
  2589→  SmallVector<int64_t> zeros(numLoops, 0);
  2590→  TileSizesListType tileSizes = {distTileSizes, distConfig.vectorSizeHints,
  2591→                                 zeros, zeros};
  2592→  return setOpConfigAndEntryPointFnTranslation(
  2593→      entryPointFn, padOp, tileSizes,
  2594→      DispatchLoweringPassPipeline::CPUDoubleTilingExpert);
  2595→}
  2596→
  2597→/// Set the default configuration for operations that implement the
  2598→/// `TiledOpInterface`.
  2599→static LogicalResult setRootConfig(mlir::FunctionOpInterface entryPointFn,
  2600→                                   TilingInterface op) {
  2601→  assert(!getLoweringConfig(op) && "expected lowering_config is not set");
  2602→  SmallVector<int64_t> distTileSizes =
  2603→      getDefaultDistributedLevelTileSizes(op, DistributionHeuristicConfig{});
  2604→  TileSizesListType tileSizes = {distTileSizes};
  2605→  SmallVector<int64_t> vecTileSizes = distTileSizes;
  2606→
  2607→  // Add an extra level of tiling.
  2608→  // TODO: Limit vector tile sizes for other TilingInterface ops.
  2609→  if (auto linalgOp = dyn_cast<linalg::LinalgOp>(*op)) {
  2610→    limitVectorTileSizes(linalgOp, vecTileSizes);
  2611→  }
  2612→  tileSizes.push_back(vecTileSizes);
  2613→  return setOpConfigAndEntryPointFnTranslation(
  2614→      entryPointFn, op, tileSizes, DispatchLoweringPassPipeline::CPUDefault);
  2615→}
